+		Since: since,
+		Limit: 0,
+	})
+	if err != nil {
+		return err
+	}
+
+	if IsJSONOutput() {
+		return output.PrintJSON(resp.Aggregations)
+	}
+
+	t := theme.Current()
+	fmt.Printf("%sAgent Insights (Since %s)%s\n", "\033[1m", since, "\033[0m")
+	
+	if resp.Aggregations != nil {
